/**
 * Analytics summary with aggregate platform stats.
 */
export interface AnalyticsSummary {
  totalUsers: number;
  totalOrders: number;
  revenue: number;
  activeUsers: number;
}

/**
 * Per-user analytics data.
 */
export interface UserAnalytics {
  userId: string;
  orderCount: number;
  totalSpent: number;
  lastActive: Date | null;
}

/**
 * A single data point in a time-series trend.
 */
export interface TrendPoint {
  timestamp: Date;
  metric: string;
  value: number;
}

/**
 * Analytics service — aggregates data from users and orders
 * to produce dashboard-level analytics.
 *
 * Depends on:
 * - UserRepository (data layer) for user data
 * - OrderRepository (data layer) for order data
 */

import type { AnalyticsSummary, UserAnalytics, TrendPoint } from '../models/analytics.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type { OrderRepository } from '../repositories/order.repository.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private userRepository: UserRepository,
    private orderRepository: OrderRepository,
  ) {}

  /**
   * Get aggregate platform summary stats.
   */
  getSummary(): AnalyticsSummary {
    this.logger.info('Generating analytics summary');

    const users = this.userRepository.findAll();
    const orders = this.orderRepository.findAll();

    const revenue = orders.reduce((sum, order) => sum + order.total, 0);

    const userIdsWithOrders = new Set(orders.map((o) => o.userId));
    const activeUsers = userIdsWithOrders.size;

    return {
      totalUsers: users.length,
      totalOrders: orders.length,
      revenue,
      activeUsers,
    };
  }

  /**
   * Get analytics for a specific user.
   */
  getUserAnalytics(userId: string): UserAnalytics {
    this.logger.info(`Generating analytics for user: ${userId}`);

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    const orders = this.orderRepository.findByUserId(userId);
    const totalSpent = orders.reduce((sum, order) => sum + order.total, 0);

    let lastActive: Date | null = null;
    if (orders.length > 0) {
      lastActive = orders.reduce(
        (latest, order) => (order.createdAt > latest ? order.createdAt : latest),
        orders[0]!.createdAt,
      );
    }

    return {
      userId,
      orderCount: orders.length,
      totalSpent,
      lastActive,
    };
  }

  /**
   * Get time-series trend data for a given metric within a date range.
   *
   * Supported metrics: 'orders', 'revenue'.
   */
  getTrends(metric: string, startDate: Date, endDate: Date): TrendPoint[] {
    this.logger.info(`Generating trends for metric: ${metric}`);

    if (metric !== 'orders' && metric !== 'revenue') {
      throw new Error(`Unsupported metric: ${metric}`);
    }

    const orders = this.orderRepository.findAll(
      (order) => order.createdAt >= startDate && order.createdAt <= endDate,
    );

    // Group orders by date (day granularity)
    const buckets = new Map<string, typeof orders>();
    for (const order of orders) {
      const key = order.createdAt.toISOString().slice(0, 10);
      const bucket = buckets.get(key);
      if (bucket) {
        bucket.push(order);
      } else {
        buckets.set(key, [order]);
      }
    }

    // Build sorted trend points
    const points: TrendPoint[] = [];
    const sortedKeys = [...buckets.keys()].sort();

    for (const key of sortedKeys) {
      const dayOrders = buckets.get(key)!;
      const value =
        metric === 'orders'
          ? dayOrders.length
          : dayOrders.reduce((sum, o) => sum + o.total, 0);

      points.push({
        timestamp: new Date(key),
        metric,
        value,
      });
    }

    return points;
  }
}

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-1',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date('2026-01-15'),
    updatedAt: new Date('2026-01-15'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> = {}): Order {
  return {
    id: 'order-1',
    userId: 'user-1',
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 50 }],
    total: 50,
    status: 'pending',
    createdAt: new Date('2026-02-01'),
    updatedAt: new Date('2026-02-01'),
    ...overrides,
  };
}

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(userRepo, orderRepo);
  });

  describe('getSummary', () => {
    it('should return zeros when no data exists', () => {
      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(0);
      expect(summary.totalOrders).toBe(0);
      expect(summary.revenue).toBe(0);
      expect(summary.activeUsers).toBe(0);
    });

    it('should aggregate stats from users and orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));
      userRepo.save(makeUser({ id: 'user-3', email: 'carol@example.com' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-1', total: 50 }));
      orderRepo.save(makeOrder({ id: 'order-3', userId: 'user-2', total: 75 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(3);
      expect(summary.totalOrders).toBe(3);
      expect(summary.revenue).toBe(225);
      expect(summary.activeUsers).toBe(2);
    });

    it('should count active users as those with orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 30 }));

      const summary = service.getSummary();

      expect(summary.totalUsers).toBe(2);
      expect(summary.activeUsers).toBe(1);
    });
  });

  describe('getUserAnalytics', () => {
    it('should throw for non-existent user', () => {
      expect(() => service.getUserAnalytics('nonexistent')).toThrow('User not found');
    });

    it('should return zero stats for user with no orders', () => {
      userRepo.save(makeUser({ id: 'user-1' }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(0);
      expect(analytics.totalSpent).toBe(0);
      expect(analytics.lastActive).toBeNull();
    });

    it('should aggregate order data for a user', () => {
      userRepo.save(makeUser({ id: 'user-1' }));

      orderRepo.save(makeOrder({
        id: 'order-1',
        userId: 'user-1',
        total: 100,
        createdAt: new Date('2026-01-10'),
      }));
      orderRepo.save(makeOrder({
        id: 'order-2',
        userId: 'user-1',
        total: 50,
        createdAt: new Date('2026-03-20'),
      }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.userId).toBe('user-1');
      expect(analytics.orderCount).toBe(2);
      expect(analytics.totalSpent).toBe(150);
      expect(analytics.lastActive).toEqual(new Date('2026-03-20'));
    });

    it('should not include orders from other users', () => {
      userRepo.save(makeUser({ id: 'user-1' }));
      userRepo.save(makeUser({ id: 'user-2', email: 'bob@example.com' }));

      orderRepo.save(makeOrder({ id: 'order-1', userId: 'user-1', total: 100 }));
      orderRepo.save(makeOrder({ id: 'order-2', userId: 'user-2', total: 200 }));

      const analytics = service.getUserAnalytics('user-1');

      expect(analytics.orderCount).toBe(1);
      expect(analytics.totalSpent).toBe(100);
    });
  });

  describe('getTrends', () => {
    it('should throw for unsupported metric', () => {
      expect(() =>
        service.getTrends('invalid', new Date('2026-01-01'), new Date('2026-12-31')),
      ).toThrow('Unsupported metric');
    });

    it('should return empty array when no orders in range', () => {
      const trends = service.getTrends('orders', new Date('2026-01-01'), new Date('2026-01-31'));

      expect(trends).toHaveLength(0);
    });

    it('should return order count trends', () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-02-01'), total: 10 }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2026-02-01'), total: 20 }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2026-02-03'), total: 30 }));

      const trends = service.getTrends('orders', new Date('2026-01-01'), new Date('2026-03-01'));

      expect(trends).toHaveLength(2);
      expect(trends[0]!.timestamp).toEqual(new Date('2026-02-01'));
      expect(trends[0]!.metric).toBe('orders');
      expect(trends[0]!.value).toBe(2);
      expect(trends[1]!.value).toBe(1);
    });

    it('should return revenue trends', () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-02-01'), total: 100 }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2026-02-01'), total: 50 }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2026-02-03'), total: 75 }));

      const trends = service.getTrends('revenue', new Date('2026-01-01'), new Date('2026-03-01'));

      expect(trends).toHaveLength(2);
      expect(trends[0]!.value).toBe(150);
      expect(trends[1]!.value).toBe(75);
    });

    it('should only include orders within the date range', () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-01-15'), total: 10 }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2026-02-15'), total: 20 }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2026-03-15'), total: 30 }));

      const trends = service.getTrends('orders', new Date('2026-02-01'), new Date('2026-02-28'));

      expect(trends).toHaveLength(1);
      expect(trends[0]!.value).toBe(1);
    });

    it('should return trend points sorted by date', () => {
      orderRepo.save(makeOrder({ id: 'o1', createdAt: new Date('2026-02-10'), total: 10 }));
      orderRepo.save(makeOrder({ id: 'o2', createdAt: new Date('2026-02-05'), total: 20 }));
      orderRepo.save(makeOrder({ id: 'o3', createdAt: new Date('2026-02-15'), total: 30 }));

      const trends = service.getTrends('orders', new Date('2026-01-01'), new Date('2026-03-01'));

      expect(trends).toHaveLength(3);
      expect(trends[0]!.timestamp < trends[1]!.timestamp).toBe(true);
      expect(trends[1]!.timestamp < trends[2]!.timestamp).toBe(true);
    });
  });
});

